SELECT [Geographical Zone].Description AS Geo1, [Geographical Zone_1].Description AS Geo2, Customer.No_ AS CodiceCliente, Customer.Name AS Cliente, Salesperson_Purchaser.Code AS CodiceAgente, Salesperson_Purchaser.Name AS Agente, [Cust_ Ledger Entry].[Document Type] AS TipoDocumentoFattura, IIf([tipodocumentofattura]=2,"FATT",IIf([tipodocumentofattura]=3,"NDC","???")) AS DescrTipo, [Cust_ Ledger Entry].[Document No_] AS NumeroDocumentoFattura, tempiPag_New_step7_TuttiIMovimenti.ChiaveMovimentoFatturaNotaCredito, [Cust_ Ledger Entry_1].[Document Type] AS TipoDocumentoPagamento, [Cust_ Ledger Entry_1].[Document No_] AS NumeroDocumentoPagamento, tempiPag_New_step7_TuttiIMovimenti.ChiaveMovimentoPagamento, tempiPag_New_step5_CalcoloDelloImportoEStatusPerEntryNo.status, tempiPag_New_step7_TuttiIMovimenti.collegamento, tempiPag_New_step7_TuttiIMovimenti.Importoabbinato, tempiPag_New_step7_TuttiIMovimenti.testComp, [Cust_ Ledger Entry].[Document Date] AS DataFattura, [Cust_ Ledger Entry].[Due Date] AS DataScadenzaPagamento, IIf([collegamento]<>"Residuo",IIf([Cust_ Ledger Entry_1.Document type]<>3,[Cust_ Ledger Entry_1.due date],[Cust_ Ledger Entry_1.document date]),[forms]![principale]![datapagamentoposizioniscoperte]) AS DataPagamento, [Cust_ Ledger Entry].[Dimension Set ID], Customer.[SKIP CREDIT INFO UPDATE], [Cust_ Ledger Entry].[Payment Method Code] AS [Payment Method Code_CustLedgEnrty], Customer.[Payment Method Code], Customer.[Payment Terms Code], [Cust_ Ledger Entry].[Managed by Lawyer] AS [Managed by Lawyer_FatturaNDC], [Cust_ Ledger Entry_1].[Managed by Lawyer] AS [Managed by Lawyer_Pagamento]
FROM ((((tempiPag_New_step7_TuttiIMovimenti LEFT JOIN [Cust_ Ledger Entry] AS [Cust_ Ledger Entry_1] ON tempiPag_New_step7_TuttiIMovimenti.ChiaveMovimentoPagamento = [Cust_ Ledger Entry_1].[Entry No_]) INNER JOIN (([Cust_ Ledger Entry] INNER JOIN Customer ON [Cust_ Ledger Entry].[Customer No_] = Customer.No_) LEFT JOIN Salesperson_Purchaser ON [Cust_ Ledger Entry].[Salesperson Code] = Salesperson_Purchaser.Code) ON tempiPag_New_step7_TuttiIMovimenti.ChiaveMovimentoFatturaNotaCredito = [Cust_ Ledger Entry].[Entry No_]) INNER JOIN tempiPag_New_step5_CalcoloDelloImportoEStatusPerEntryNo ON tempiPag_New_step7_TuttiIMovimenti.ChiaveMovimentoFatturaNotaCredito = tempiPag_New_step5_CalcoloDelloImportoEStatusPerEntryNo.[Entry No_]) LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].Code;

